+      if (dependency !== undefined) return dependency;
+    }
+  }
+  return undefined;
+}
+
+function getOptionNames(usage: Usage): readonly string[] {
+  const names: string[] = [];
+  for (const term of usage) {
+    if (term.type === "option") names.push(...term.names);
+    else if (term.type === "optional" || term.type === "multiple") {
+      names.push(...getOptionNames(term.terms));
+    }
+  }
+  return names;
+}
+
+function unwrapOptionState(state: unknown): unknown {
+  if (Array.isArray(state) && state.length === 1) {
+    return unwrapOptionState(state[0]);
+  }
+  if (state !== null && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: unknown; readonly value?: unknown };
+    return result.success === true ? result.value : undefined;
+  }
+  return state;
+}
