+function isProvidedState(state: unknown, initialState: unknown): boolean {
+  if (state === initialState || state === undefined) return false;
+  if (Array.isArray(state) && state.length === 1) {
+    return isProvidedState(state[0], undefined);
+  }
+  return state !== null && typeof state === "object" &&
