+  return fields.find((field) => String(field.key) === option) ??
+    fields.find((field) => getOptionNames(field.parser.usage).includes(option));
+}
+
+function conditionSatisfied(
+  condition: OptionDependencyCondition,
+  fields: readonly DependencyField[],
+  state: Record<string | symbol, unknown>,
+): boolean {
+  const field = resolveDependencyField(condition.option, fields);
+  if (field === undefined) return false;
+  const value = unwrapOptionState(state[field.key]);
+  return "value" in condition ? value === condition.value : Boolean(value);
+}
+
+function dependencySatisfied(
+  dependency: OptionDependency,
+  fields: readonly DependencyField[],
+  state: Record<string | symbol, unknown>,
+): boolean {
+  const single = dependency.option === undefined
+    ? true
+    : conditionSatisfied(dependency, fields, state);
+  const allOf = dependency.allOf === undefined
+    ? true
+    : dependency.allOf.every((condition) =>
+      conditionSatisfied(condition, fields, state)
+    );
+  const anyOf = dependency.anyOf === undefined
+    ? true
+    : dependency.anyOf.some((condition) =>
+      conditionSatisfied(condition, fields, state)
+    );
+  return single && allOf && anyOf;
+}
